import{bQ as a,aL as d,u as e,G as i}from"./chunks/framework.D06dwy5q.js";const A=JSON.parse('{"title":"负载均衡基础","description":"","frontmatter":{},"headers":[],"relativePath":"08.负载均衡与高可用/01-负载均衡基础.md","filePath":"08.负载均衡与高可用/01-负载均衡基础.md","lastUpdated":null}'),s={name:"08.负载均衡与高可用/01-负载均衡基础.md"};function r(h,t,l,p,n,o){return d(),e("div",null,[...t[0]||(t[0]=[i(`<h1 id="负载均衡基础" tabindex="-1">负载均衡基础 <a class="header-anchor" href="#负载均衡基础" aria-label="Permalink to &quot;负载均衡基础&quot;">​</a></h1><p>单台服务器有物理上限——CPU、内存、网络带宽都是有限的。一台机器扛不住的时候，加机器是自然的选择。但加了机器之后，客户端请求怎么知道该发给谁？手动给客户端一个 IP 列表，让客户端自己轮询？后端挂了谁把流量切走？后端之间负载不均衡怎么调？</p><p>负载均衡就是解决&quot;多台机器一起服务时，请求怎么分、故障怎么摘、入口怎么不成为单点&quot;这一组问题。日常关注点在四层和七层区别、调度算法、健康检查、会话保持、故障摘除和入口高可用。</p><h2 id="一、先分清两个问题" tabindex="-1">一、先分清两个问题 <a class="header-anchor" href="#一、先分清两个问题" aria-label="Permalink to &quot;一、先分清两个问题&quot;">​</a></h2><p>负载均衡和高可用经常一起出现，但它们不是一回事。</p><table tabindex="0"><thead><tr><th>问题</th><th>关注点</th><th>常见方案</th></tr></thead><tbody><tr><td>负载均衡</td><td>请求怎么分到多台后端</td><td>LVS、HAProxy、Nginx、云负载均衡</td></tr><tr><td>高可用</td><td>当前入口坏了以后谁接管</td><td>Keepalived、云厂商 VIP、DNS、集群控制面</td></tr></tbody></table><p>一个简单链路：</p><div class="mermaid-diagram" data-mermaid-code="flowchart%20LR%0A%20%20%20%20client%5B%22%E5%AE%A2%E6%88%B7%E7%AB%AF%22%5D%20--%3E%20lb%5B%22%E8%B4%9F%E8%BD%BD%E5%9D%87%E8%A1%A1%E5%85%A5%E5%8F%A3%22%5D%0A%20%20%20%20lb%20--%3E%20web01%5B%22%E5%90%8E%E7%AB%AF%20web01%22%5D%0A%20%20%20%20lb%20--%3E%20web02%5B%22%E5%90%8E%E7%AB%AF%20web02%22%5D%0A%20%20%20%20lb%20--%3E%20web03%5B%22%E5%90%8E%E7%AB%AF%20web03%22%5D%0A"></div><p>带高可用入口：</p><div class="mermaid-diagram" data-mermaid-code="flowchart%20LR%0A%20%20%20%20client%5B%22%E5%AE%A2%E6%88%B7%E7%AB%AF%22%5D%20--%3E%20vip%5B%22VIP%22%5D%0A%20%20%20%20vip%20--%3E%20active%5B%22%E4%B8%BB%E5%85%A5%E5%8F%A3%E8%8A%82%E7%82%B9%22%5D%0A%20%20%20%20vip%20-.%20%22%E5%A4%87%E7%94%A8%22%20.-%3E%20standby%5B%22%E5%A4%87%E7%94%A8%E5%85%A5%E5%8F%A3%E8%8A%82%E7%82%B9%22%5D%0A%20%20%20%20active%20--%3E%20backend%5B%22%E5%90%8E%E7%AB%AF%E6%9C%8D%E5%8A%A1%22%5D%0A"></div><p>这两个问题分开设计更清晰：先确认流量如何分发，再确认入口故障时怎么切换。只搭一个负载均衡实例，后端再多也挡不住入口单点。</p><h2 id="二、四层和七层" tabindex="-1">二、四层和七层 <a class="header-anchor" href="#二、四层和七层" aria-label="Permalink to &quot;二、四层和七层&quot;">​</a></h2><p>四层负载均衡工作在 TCP/UDP 连接层。它主要看 IP、端口和连接信息，不理解 HTTP URI、Header、Cookie。</p><p>七层负载均衡工作在应用层。HTTP 场景下，它可以看域名、路径、Header、Cookie、状态码和响应时间。</p><table tabindex="0"><thead><tr><th>类型</th><th>看什么</th><th>常见能力</th><th>常见工具</th></tr></thead><tbody><tr><td>四层</td><td>IP、端口、TCP/UDP 连接</td><td>转发、连接调度、吞吐高</td><td>LVS、云四层 LB</td></tr><tr><td>七层</td><td>HTTP 请求内容</td><td>域名路由、路径路由、Header、Cookie、TLS</td><td>HAProxy、Nginx、云七层 LB</td></tr></tbody></table><p>例子：</p><table tabindex="0"><thead><tr><th>需求</th><th>更适合</th></tr></thead><tbody><tr><td>MySQL 3306 TCP 转发</td><td>四层</td></tr><tr><td>Redis 6379 TCP 转发</td><td>四层</td></tr><tr><td><code>api.example.com</code> 转发到 API 集群</td><td>七层</td></tr><tr><td><code>/admin/</code> 和 <code>/api/</code> 走不同后端</td><td>七层</td></tr><tr><td>按 Cookie 做会话保持</td><td>七层</td></tr></tbody></table><p>四层不是“低级”，七层也不是天然更好。四层路径短、性能好、协议透明；七层可观察性和规则能力更强，但也更容易把入口规则写复杂。</p><h2 id="三、常见架构" tabindex="-1">三、常见架构 <a class="header-anchor" href="#三、常见架构" aria-label="Permalink to &quot;三、常见架构&quot;">​</a></h2><p>单入口负载均衡：</p><div class="mermaid-diagram" data-mermaid-code="flowchart%20TD%0A%20%20%20%20client%5B%22%E5%AE%A2%E6%88%B7%E7%AB%AF%22%5D%20--%3E%20lb%5B%22%E8%B4%9F%E8%BD%BD%E5%9D%87%E8%A1%A1%E5%85%A5%E5%8F%A3%22%5D%0A%20%20%20%20lb%20--%3E%20web01%5B%22%E5%90%8E%E7%AB%AF%20web01%22%5D%0A%20%20%20%20lb%20--%3E%20web02%5B%22%E5%90%8E%E7%AB%AF%20web02%22%5D%0A"></div><p>双入口高可用：</p><div class="mermaid-diagram" data-mermaid-code="flowchart%20TD%0A%20%20%20%20client%5B%22%E5%AE%A2%E6%88%B7%E7%AB%AF%22%5D%20--%3E%20vip%5B%22VIP%22%5D%0A%20%20%20%20vip%20--%3E%20lb01%5B%22lb01%20%E4%B8%BB%E5%85%A5%E5%8F%A3%22%5D%0A%20%20%20%20vip%20-.%20%22%E5%A4%87%E7%94%A8%22%20.-%3E%20lb02%5B%22lb02%20%E5%A4%87%E7%94%A8%E5%85%A5%E5%8F%A3%22%5D%0A%20%20%20%20lb01%20--%3E%20web01%5B%22%E5%90%8E%E7%AB%AF%20web01%22%5D%0A%20%20%20%20lb01%20--%3E%20web02%5B%22%E5%90%8E%E7%AB%AF%20web02%22%5D%0A%20%20%20%20lb02%20-.%20%22%E6%8E%A5%E7%AE%A1%E5%90%8E%E8%BD%AC%E5%8F%91%22%20.-%3E%20web01%0A%20%20%20%20lb02%20-.%20%22%E6%8E%A5%E7%AE%A1%E5%90%8E%E8%BD%AC%E5%8F%91%22%20.-%3E%20web02%0A"></div><p>多层入口：</p><div class="mermaid-diagram" data-mermaid-code="flowchart%20LR%0A%20%20%20%20client%5B%22%E5%AE%A2%E6%88%B7%E7%AB%AF%22%5D%20--%3E%20cloudlb%5B%22%E4%BA%91%E8%B4%9F%E8%BD%BD%E5%9D%87%E8%A1%A1%22%5D%0A%20%20%20%20cloudlb%20--%3E%20proxy%5B%22Nginx%20%2F%20HAProxy%22%5D%0A%20%20%20%20proxy%20--%3E%20app%5B%22%E5%BA%94%E7%94%A8%E6%9C%8D%E5%8A%A1%22%5D%0A"></div><p>多层入口不是越多越稳。每多一层，就多一份超时、日志、真实 IP、健康检查和故障定位成本。小环境里两层已经够用：一层 VIP/云 LB，一层七层代理。</p><h2 id="四、调度算法" tabindex="-1">四、调度算法 <a class="header-anchor" href="#四、调度算法" aria-label="Permalink to &quot;四、调度算法&quot;">​</a></h2><p>常见算法：</p><table tabindex="0"><thead><tr><th>算法</th><th>含义</th><th>适用情况</th></tr></thead><tbody><tr><td>轮询</td><td>请求依次分给后端</td><td>后端规格接近，请求耗时接近</td></tr><tr><td>加权轮询</td><td>权重大分到更多请求</td><td>后端机器规格不同</td></tr><tr><td>最少连接</td><td>分给当前连接少的后端</td><td>请求耗时差异大</td></tr><tr><td>源地址哈希</td><td>同一来源尽量打到同一后端</td><td>简单会话保持</td></tr><tr><td>URI 哈希</td><td>同一 URI 尽量打到同一后端</td><td>缓存类服务</td></tr></tbody></table><p>调度算法只能决定“怎么分”，不能修好后端本身。后端接口慢、数据库慢、GC 卡顿时，换算法通常只是让故障表现变得不一样。</p><h2 id="五、健康检查" tabindex="-1">五、健康检查 <a class="header-anchor" href="#五、健康检查" aria-label="Permalink to &quot;五、健康检查&quot;">​</a></h2><p>健康检查用于判断后端是否还能接流量。常见检查方式：</p><table tabindex="0"><thead><tr><th>类型</th><th>检查内容</th><th>优缺点</th></tr></thead><tbody><tr><td>TCP 检查</td><td>端口能否连接</td><td>简单，但只能说明端口开着</td></tr><tr><td>HTTP 检查</td><td>请求健康接口</td><td>更接近业务，但接口要写得轻</td></tr><tr><td>脚本检查</td><td>自定义逻辑</td><td>灵活，维护成本高</td></tr></tbody></table><p>HTTP 健康检查常见路径：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/health</span></span>
<span class="line"><span>/ready</span></span>
<span class="line"><span>/actuator/health</span></span></code></pre></div><p>健康检查接口要轻，通常只检查进程是否可服务、关键依赖是否可用。把复杂数据库查询塞进健康检查，会让入口层自己制造压力。</p><h2 id="六、会话保持" tabindex="-1">六、会话保持 <a class="header-anchor" href="#六、会话保持" aria-label="Permalink to &quot;六、会话保持&quot;">​</a></h2><p>会话保持是让同一个用户尽量访问同一台后端。常见方式：</p><table tabindex="0"><thead><tr><th>方式</th><th>说明</th><th>风险</th></tr></thead><tbody><tr><td>源 IP 哈希</td><td>同一来源 IP 固定到后端</td><td>NAT 场景下很多用户是同一 IP</td></tr><tr><td>Cookie</td><td>入口写入或读取 Cookie</td><td>只适合 HTTP</td></tr><tr><td>后端共享 session</td><td>session 放 Redis/数据库</td><td>应用要支持</td></tr><tr><td>无状态 token</td><td>登录态不依赖单台后端</td><td>应用改造更多</td></tr></tbody></table><p>源 IP 哈希很方便，但办公室出口、运营商 NAT、移动网络都会让 IP 分布变形。核心业务多实例部署时，把 session 外置或做无状态登录比依赖入口层粘住某台机器更可靠。</p><h2 id="七、真实-ip" tabindex="-1">七、真实 IP <a class="header-anchor" href="#七、真实-ip" aria-label="Permalink to &quot;七、真实 IP&quot;">​</a></h2><p>七层代理后，后端看到的来源 IP 可能是代理地址。HTTP 场景通常靠请求头传递：</p><div class="language-nginx vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">nginx</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">proxy_set_header </span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">X-Real-IP $remote_addr;</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">proxy_set_header </span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">X-Forwarded-For $proxy_add_x_forwarded_for;</span></span></code></pre></div><p>HAProxy 常见：</p><div class="language-haproxy vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">haproxy</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>option forwardfor  # 在 X-Forwarded-For 里追加客户端 IP</span></span></code></pre></div><p>多层代理时，真实 IP 要配可信代理范围。应用直接相信客户端传来的 <code>X-Forwarded-For</code>，日志和限流都会被伪造。</p><h2 id="八、常见方案对比" tabindex="-1">八、常见方案对比 <a class="header-anchor" href="#八、常见方案对比" aria-label="Permalink to &quot;八、常见方案对比&quot;">​</a></h2><table tabindex="0"><thead><tr><th>方案</th><th>层次</th><th>特点</th><th>常见场景</th></tr></thead><tbody><tr><td>LVS</td><td>四层</td><td>内核 IPVS，性能高，配置偏网络</td><td>TCP 高吞吐入口</td></tr><tr><td>HAProxy</td><td>四层/七层</td><td>健康检查、ACL、统计清楚</td><td>API、Web、TCP 代理</td></tr><tr><td>Nginx</td><td>七层为主</td><td>静态资源、反向代理、TLS 常用</td><td>Web 入口、静态站点</td></tr><tr><td>Keepalived</td><td>高可用</td><td>VRRP、VIP 漂移</td><td>给 LVS/HAProxy/Nginx 做入口 HA</td></tr><tr><td>云负载均衡</td><td>四层/七层</td><td>托管，少维护机器</td><td>云上生产入口</td></tr></tbody></table><h2 id="九、排查入口" tabindex="-1">九、排查入口 <a class="header-anchor" href="#九、排查入口" aria-label="Permalink to &quot;九、排查入口&quot;">​</a></h2><p>负载均衡故障常见分层：</p><table tabindex="0"><thead><tr><th>层</th><th>检查项</th></tr></thead><tbody><tr><td>客户端到入口</td><td>DNS、VIP、端口、防火墙</td></tr><tr><td>入口自身</td><td>进程、监听、配置、日志</td></tr><tr><td>健康检查</td><td>后端是否被摘除</td></tr><tr><td>入口到后端</td><td>路由、防火墙、后端端口</td></tr><tr><td>后端应用</td><td>状态码、响应时间、应用日志</td></tr></tbody></table><p>常用命令：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">ss</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -lntp</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">                 # 看入口监听端口</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">curl</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -I</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> http://vip/</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">      # 从入口访问</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">curl</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -I</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> http://backend/</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">  # 绕过入口访问后端</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">tcpdump</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -nn</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> host</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 10.0.0.10</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> and</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> port</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 80</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">  # 看流量是否到达指定主机</span></span></code></pre></div><p>我排查这类问题时会先做两次访问：访问 VIP，再直接访问后端。VIP 不通但后端通，入口层优先；后端也不通，就回到应用、端口和网络。</p>`,54)])])}const b=a(s,[["render",r]]);export{A as __pageData,b as default};
